solution_code:
#include <iostream>
#include <cstddef>

std::size_t pointerSizeof(const int* arr)
{
    return sizeof(arr);
}

int findMax(const int* arr, int length)
{
    int max{ arr[0] };
    for (int i{ 1 }; i < length; ++i)
    {
        if (arr[i] > max)
            max = arr[i];
    }
    return max;
}

int main()
{
    int n{};
    std::cin >> n;

    int arr[10]{};
    for (int i{ 0 }; i < n; ++i)
        std::cin >> arr[i];

    std::cout << "array sizeof: " << sizeof(arr) << '\n';
    std::cout << "pointer sizeof: " << pointerSizeof(arr) << '\n';
    std::cout << "max: " << findMax(arr, n) << '\n';

    return 0;
}
